// Auto-login once for Cart requests. Does not modify environment file.
if (!pm.collectionVariables.get("runtimeToken")) {
    const baseUrl = pm.environment.get("baseUrl") || "http://localhost:8080";
    const username = pm.environment.get("loginUsername") || ("cartuser_" + Date.now());
    const password = pm.environment.get("loginPassword") || "Cart@Test123";

    pm.sendRequest({
        url: baseUrl + "/api/auth/login",
        method: "POST",
        header: { "Content-Type": "application/json" },
        body: { mode: "raw", raw: JSON.stringify({ username, password }) }
    }, function (err, res) {
        let token = null;
        try { token = res && res.json() && res.json().token; } catch (e) {}

        if (token) {
            pm.collectionVariables.set("runtimeToken", token);
            return;
        }

        const newUsername = "cartuser_" + Date.now();
        const newEmail = newUsername + "@example.com";
        const newPassword = "Cart@Test123";

        pm.sendRequest({
            url: baseUrl + "/api/auth/register",
            method: "POST",
            header: { "Content-Type": "application/json" },
            body: { mode: "raw", raw: JSON.stringify({
                username: newUsername,
                email: newEmail,
                password: newPassword,
                fullName: "Cart BlackBox User"
            }) }
        }, function (regErr, regRes) {
            let regToken = null;
            try { regToken = regRes && regRes.json() && regRes.json().token; } catch (e) {}
            if (regToken) {
                pm.collectionVariables.set("runtimeToken", regToken);
            }
        });
    });
}

